#!/usr/bin/env python3
"""gate_runner.py — check eval metrics against thresholds before promotion."""
import json
import sys
from pathlib import Path

GATE_CONFIG = {
    "eval_pass_rate": {"min": 0.90, "max_regression_vs_baseline": 0.02},
    "p95_latency_seconds": {"max": 3.0},
    "security_critical_cves": {"max": 0},
}

def load_results(path: str) -> dict:
    return json.loads(Path(path).read_text())

def run_gates(results: dict, baseline: dict) -> list[str]:
    """Return a list of gate failure messages; empty list means all passed."""
    failures = []

    pass_rate = results["eval_pass_rate"]
    min_rate = GATE_CONFIG["eval_pass_rate"]["min"]
    if pass_rate < min_rate:
        failures.append(f"eval_pass_rate {pass_rate:.1%} < threshold {min_rate:.1%}")

    regression = baseline["eval_pass_rate"] - pass_rate
    max_reg = GATE_CONFIG["eval_pass_rate"]["max_regression_vs_baseline"]
    if regression > max_reg:
        failures.append(
            f"eval regression {regression:.1%} exceeds max {max_reg:.1%} vs baseline"
        )

    p95 = results["p95_latency_seconds"]
    if p95 > GATE_CONFIG["p95_latency_seconds"]["max"]:
        failures.append(f"p95 latency {p95:.2f}s exceeds SLA 3.00s")

    if results.get("security_critical_cves", 0) > 0:
        failures.append("critical CVEs detected in image scan")

    return failures

if __name__ == "__main__":
    results = load_results("eval-results.json")
    baseline = load_results("baseline-results.json")
    failures = run_gates(results, baseline)
    if failures:
        print("GATE BLOCKED:")
        for f in failures:
            print(f"  ✗ {f}")
        sys.exit(1)
    print("All gates passed — artifact eligible for promotion.")
    sys.exit(0)
